import hashlib, hmac, json, time
from dataclasses import dataclass, field

SIGNING_KEY = b"rag-index-signing-key-change-in-prod"

@dataclass
class IndexedDocument:
    doc_id: str
    text: str
    source_url: str
    ingested_at: float = field(default_factory=time.time)
    signature: str = ""

    def compute_signature(self) -> str:
        payload = json.dumps({
            "doc_id": self.doc_id,
            "text": self.text,
            "source_url": self.source_url,
            "ingested_at": self.ingested_at,
        }, sort_keys=True).encode()
        return hmac.new(SIGNING_KEY, payload, hashlib.sha256).hexdigest()

    def sign(self) -> "IndexedDocument":
        self.signature = self.compute_signature()
        return self

    def is_valid(self) -> bool:
        return hmac.compare_digest(self.signature, self.compute_signature())


# At retrieval time, verify every chunk before injecting into the prompt
def verified_chunks(raw_results: list[dict]) -> list[str]:
    safe = []
    for raw in raw_results:
        doc = IndexedDocument(**raw)
        if not doc.is_valid():
            # Log and skip — do NOT surface unsigned content to the model
            raise ValueError(
                f"RAG document '{doc.doc_id}' failed signature check; "
                "possible index tampering detected."
            )
        safe.append(doc.text)
    return safe

import hashlib, requests, os
from pathlib import Path

# Record expected SHA-256 of each model checkpoint in your infrastructure repo.
# Update this dict only via a reviewed pull request.
APPROVED_MODEL_CHECKSUMS: dict[str, str] = {
    "meta-llama/Llama-3-8B-Instruct": "a1b2c3d4e5f6...",  # truncated for illustration
    "mistralai/Mistral-7B-Instruct-v0.2": "9f8e7d6c5b4a...",
}

def sha256_file(path: Path, chunk_size: int = 1 << 20) -> str:
    h = hashlib.sha256()
    with path.open("rb") as f:
        for chunk in iter(lambda: f.read(chunk_size), b""):
            h.update(chunk)
    return h.hexdigest()

def verify_model_weights(model_id: str, local_dir: Path) -> None:
    """
    Call this immediately after downloading model weights,
    before loading them into memory.
    """
    expected = APPROVED_MODEL_CHECKSUMS.get(model_id)
    if expected is None:
        raise PermissionError(
            f"Model '{model_id}' is not in the approved checksum registry. "
            "Add it after a security review."
        )
    # Hash the primary weights file (adjust filename pattern as needed)
    weight_files = sorted(local_dir.glob("*.safetensors")) or sorted(local_dir.glob("*.bin"))
    if not weight_files:
        raise FileNotFoundError(f"No weight files found under {local_dir}")

    combined = hashlib.sha256()
    for wf in weight_files:
        combined.update(sha256_file(wf).encode())
    actual = combined.hexdigest()

    if not hmac.compare_digest(actual, expected):
        raise ValueError(
            f"Checksum mismatch for '{model_id}'!\n"
            f"  Expected: {expected}\n"
            f"  Got:      {actual}\n"
            "Do NOT load these weights. Investigate before proceeding."
        )

from dataclasses import dataclass, field
from enum import Enum
import hashlib, time

class ProvenanceStatus(Enum):
    PENDING_REVIEW = "pending_review"
    APPROVED       = "approved"
    REJECTED       = "rejected"

@dataclass
class DataRecord:
    record_id: str
    content_hash: str        # SHA-256 of the raw content
    source_uri: str          # where the data came from (URL, path, API)
    contributor: str         # who or what system ingested it
    ingested_at: float = field(default_factory=time.time)
    reviewed_by: str | None = None
    status: ProvenanceStatus = ProvenanceStatus.PENDING_REVIEW

    @classmethod
    def from_content(cls, content: bytes, source_uri: str, contributor: str) -> "DataRecord":
        h = hashlib.sha256(content).hexdigest()
        return cls(
            record_id=h[:16],
            content_hash=h,
            source_uri=source_uri,
            contributor=contributor,
        )

class DataLineageStore:
    """Append-only store; records are never deleted, only status-updated."""

    def __init__(self):
        self._records: dict[str, DataRecord] = {}

    def ingest(self, content: bytes, source_uri: str, contributor: str) -> DataRecord:
        record = DataRecord.from_content(content, source_uri, contributor)
        if record.record_id in self._records:
            return self._records[record.record_id]  # deduplicate by hash
        self._records[record.record_id] = record
        return record

    def approve(self, record_id: str, reviewer: str) -> None:
        rec = self._records[record_id]
        rec.reviewed_by = reviewer
        rec.status = ProvenanceStatus.APPROVED

    def approved_only(self) -> list[DataRecord]:
        return [r for r in self._records.values()
                if r.status == ProvenanceStatus.APPROVED]

import re
from dataclasses import dataclass

# Heuristics that flag potentially malicious training examples.
# Each check returns a list of reason strings; empty → passes.

INJECTION_PATTERNS = [
    re.compile(r"ignore (previous|prior|above) instructions", re.IGNORECASE),
    re.compile(r"you are now (DAN|jailbroken|unrestricted)", re.IGNORECASE),
    re.compile(r"(bypass|override) (safety|policy|filter)", re.IGNORECASE),
    re.compile(r"INTERNAL_EVAL|debug_mode\s*=\s*true", re.IGNORECASE),
]
MAX_EXAMPLE_CHARS = 8_000
MIN_EXAMPLE_CHARS = 10

@dataclass
class QualityResult:
    example_id: str
    passed: bool
    reasons: list[str]

def check_training_example(example_id: str, text: str) -> QualityResult:
    reasons = []
    if len(text) > MAX_EXAMPLE_CHARS:
        reasons.append(f"Too long ({len(text)} chars > {MAX_EXAMPLE_CHARS})")
    if len(text) < MIN_EXAMPLE_CHARS:
        reasons.append("Too short — likely placeholder")
    for pat in INJECTION_PATTERNS:
        if pat.search(text):
            reasons.append(f"Injection pattern: {pat.pattern!r}")
    # Detect high ratio of special/control characters (obfuscation signal)
    ctrl_count = sum(1 for ch in text if ord(ch) < 32 and ch not in "\n\t")
    if ctrl_count / max(len(text), 1) > 0.02:
        reasons.append(f"High control-character ratio: {ctrl_count}/{len(text)}")
    return QualityResult(
        example_id=example_id,
        passed=len(reasons) == 0,
        reasons=reasons,
    )

def gate_dataset(examples: list[tuple[str, str]]) -> list[QualityResult]:
    results = [check_training_example(eid, text) for eid, text in examples]
    failures = [r for r in results if not r.passed]
    if failures:
        for f in failures:
            print(f"BLOCKED {f.example_id}: {f.reasons}")
        raise ValueError(
            f"{len(failures)}/{len(results)} examples failed quality gate — "
            "dataset blocked from fine-tuning pipeline."
        )
    return results
